// Syntax Blueprint:
// 1. Initialization (Start)
int counter = 0; 

// 2. Condition (Stop Rule)
while (counter < 5) { 
    // Code to execute
    // 3. Iteration (Step)
    counter++; 
}

// Example 1: The Predictable Countdown
int batteryLevel = 3;
while (batteryLevel > 0) {
    System.out.println("Battery at " + batteryLevel + "%");
    batteryLevel--; // Drains the battery by 1 each lap
}
System.out.println("Robot powering down.");

// Example 2: The Unknown Iteration (Keeps halving until safe)
double radiation = 100.0;
int days = 0;
while (radiation >= 10.0) {
    radiation = radiation / 2;
    days++;
}
System.out.println("Area is safe after " + days + " days.");

int hp = 100;
int lap = 0;

while (true) { // Infinite loop!
    lap++;

    if (lap == 2) {
        System.out.println("Dodged the attack!");
        continue; // Skips the damage code below and goes to lap 3
    }

    hp -= 50;
    System.out.println("Took damage! HP: " + hp);

    if (hp <= 0) {
        System.out.println("Player died.");
        break; // Ejects out of the infinite loop
    }
}

// Example 1: The Game Menu
int userChoice;
do {
    System.out.println("1. Play | 2. Quit");
    // Simulating user picking '2'
    userChoice = 2; 
} while (userChoice != 2); // Keeps showing menu until they pick 2

// Example 2: The 0-Health Action 
// Proving the loop runs at least once, even if the condition starts false.
int health = 0;
do {
    // Runs once despite health being 0!
    System.out.println("Player swings sword in final breath!");
} while (health > 0);

// Standard Example 1: Counting Up
for (int i = 1; i <= 3; i++) {
    System.out.println("Counting: " + i);
}

// Standard Example 2: Counting Down
for (int timer = 5; timer > 0; timer--) {
    System.out.println("T-Minus: " + timer);
}

// Advanced Usage: Multi-Variable Initialization
// 'i' counts up while 'j' counts down
for (int i = 0, j = 5; i <= j; i++, j--) {
    System.out.println("Pointer A: " + i + " | Pointer B: " + j);
}

// Advanced Usage: The "Ghost" Loop
// Leaves Start, Condition, and Step blank for an infinite loop
for (;;) {
    System.out.println("This will run forever until a break; is triggered.");
    break; // Added to prevent actual infinite crashing
}

// Example 1: Iterating over Strings
String[] inventory = {"Sword", "Shield", "Potion"};
for (String item : inventory) {
    System.out.println("Equipped: " + item);
}

// Example 2: Calculating a Total from Integers
int[] grades = {95, 80, 100};
int total = 0;
for (int grade : grades) {
    total += grade; // Adds each grade to the total
}
System.out.println("Total points: " + total);

// Example 1: Labeled break (Total Shutdown)
RadarSystem: for (int sector = 1; sector <= 3; sector++) {
    for (int blip = 1; blip <= 3; blip++) {
        if (sector == 2 && blip == 2) {
            System.out.println("Critical error! Shutting down entire RadarSystem.");
            break RadarSystem; // Kills the OUTER loop, stopping everything.
        }
        System.out.println("Sector " + sector + " - Blip " + blip);
    }
}

// Example 2: Labeled continue (Hard Skip)
SearchGrid: for (int row = 1; row <= 3; row++) {
    for (int col = 1; col <= 3; col++) {
        if (row == 2 && col == 1) {
            System.out.println("Row 2 is blocked. Skipping to Row 3.");
            continue SearchGrid; // Aborts inner loop AND forces outer loop to lap 3.
        }
        System.out.println("Searching Row " + row + ", Col " + col);
    }
}

// Example: Java Streams & .forEach() (Functional Iteration)
// Condenses massive for loops into a single line of code using Lambdas (->)
myList.forEach(item -> System.out.println(item));

List<String> inventory = List.of("Sword", "Shield", "Potion");

// The Legacy Limitation (Forward Only):
for (String item : inventory) {
    System.out.println(item);
}

// The Bleeding Edge Java 21+ Way (Backward!):
for (String item : inventory.reversed()) {
    System.out.println("Equipping last item first: " + item);
}

String[] heroes = {"Batman", "Superman", "Wonder Woman"};

// The Old Way (Explicit typing):
for (String hero : heroes) {
    System.out.println(hero);
}

// The Modern Way (Type Inference):
// The compiler looks at the array and automatically knows 'var' means 'String'
for (var hero : heroes) {
    System.out.println(hero);
}

// It works in standard for loops too!
for (var i = 0; i < 10; i++) {
    System.out.println("Lap: " + i);
}

// 1. What you type in your IDE:
for (String item : inventory) {
    System.out.println(item);
}

// 2. What the Java Compiler secretly changes it to behind your back:
Iterator<String> iterator = inventory.iterator();
while (iterator.hasNext()) {
    String item = iterator.next();
    System.out.println(item);
}

for (int i = 0; i < 5; i++) {
    System.out.print(i + " ");
}
// COMPILATION ERROR: i cannot be resolved to a variable
System.out.println("Final lap was: " + i);

// THE FIX: Declare the variable outside the loop first
int j;
for (j = 0; j < 5; j++) {
    System.out.print(j + " ");
}
System.out.println("Final lap was: " + j); // Safely prints 5

// DANGER: Infinite Loop!
for (double d = 0.0; d != 1.0; d += 0.1) {
    System.out.println("Running...");
    // 'd' jumps from 0.9 to 1.0000000000000002, skipping 1.0 exactly!
}

int x = 0;
// Print statements inside the header to prove order!
for (System.out.println("Start"); x < 2; System.out.println("Step")) {
    System.out.println("Body");
    x++;
}

/* OUTPUT TRACE:
Start
Body
Step
Body
Step
*/

// VALID: Both are ints
for (int i = 0, j = 5; i < 5; i++) {
    System.out.println(i + j);
}

// COMPILATION ERROR: Mixing int and double
for (int i = 0, double d = 5.0; i < 5; i++) {
    System.out.println("Running");
}

for (int i = 0; i < 3; i++) {
    // COMPILATION ERROR: Variable 'i' is already defined in the scope
    int i = 10; 
    System.out.println(i);
}
